const raw = $json.body ?? $json ?? {};

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return undefined;
}

function normalizeUrl(v) {
  if (v == null) return '';
  return String(v).trim();
}

function parsePositiveNumber(rawVal) {
  if (rawVal === undefined || rawVal === null || rawVal === '') return null;
  const num = Number(rawVal);
  return Number.isFinite(num) && num > 0 ? num : null;
}

function parseDurationSeconds(rawVal) {
  if (rawVal === undefined || rawVal === null || rawVal === '') return null;

  if (typeof rawVal === 'number' && Number.isFinite(rawVal)) {
    if (rawVal > 1000) return rawVal / 1000;
    return rawVal;
  }

  const s = String(rawVal).trim();
  if (!s) return null;

  const num = Number(s);
  if (Number.isFinite(num)) {
    if (num > 1000) return num / 1000;
    return num;
  }

  const hhmmss = s.match(/^(\d{1,2}):(\d{1,2})(?::(\d{1,2}(?:\.\d+)?))?$/);
  if (hhmmss) {
    if (hhmmss[3] !== undefined) {
      const h = Number(hhmmss[1] || 0);
      const m = Number(hhmmss[2] || 0);
      const sec = Number(hhmmss[3] || 0);
      return h * 3600 + m * 60 + sec;
    }
    const m = Number(hhmmss[1] || 0);
    const sec = Number(hhmmss[2] || 0);
    return m * 60 + sec;
  }

  return null;
}

function estimateTtsDuration(text) {
  const s = String(text || '').trim();
  if (!s) return null;

  const chineseChars = (s.match(/[\u4e00-\u9fa5]/g) || []).length;
  const englishWords = s
    .replace(/[\u4e00-\u9fa5]/g, ' ')
    .trim()
    .split(/\s+/)
    .filter(Boolean).length;

  let sec = 0;
  if (chineseChars > 0) sec += chineseChars / 4.2;
  if (englishWords > 0) sec += englishWords / 2.5;
  sec += 0.8;

  return Number(sec.toFixed(3));
}

const videoUrl = normalizeUrl(
  pickFirst(raw.videoUrl, raw.video_url, raw.video, raw.sourceVideoUrl, raw.source_video_url)
);
const audioUrl = normalizeUrl(pickFirst(raw.audioUrl, raw.audio_url, raw.audio, raw.voiceUrl));
const voiceRefAudioUrl = normalizeUrl(
  pickFirst(raw.voice_ref_audio_url, raw.voiceRefAudioUrl, raw.voice_ref_audio, raw.voiceRefAudio)
);
const emoRefAudioUrl = normalizeUrl(
  pickFirst(raw.emo_ref_audio_url, raw.emoRefAudioUrl, raw.emo_ref_audio, raw.emoRefAudio)
);

const scriptContent = String(
  pickFirst(raw.script_content, raw.scriptContent, raw.text, raw.content, '')
).trim();

const callbackUrl = String(
  pickFirst(raw.callbackUrl, raw.callback_url, 'https://hooks.atomx.top/webhook/digital-human-callback')
).trim();

const runninghubKey = String(
  pickFirst(raw.runninghub_key, raw.runninghubKey, raw.apiKey, 'd75f6f54beb14fee8b7379b35449332f')
).trim();

const apiKey = String(
  pickFirst(raw.api_key, raw.user_api_key, raw.userApiKey, '')
).trim();

const workflowIdFromUser = String(
  pickFirst(raw.workflow_id, raw.workflowId, 'flow_digital_human_video_lipsync')
).trim();

const workflowName = String(
  pickFirst(raw.workflow_name, raw.workflowName, '数字人视频对口型')
).trim();

const modeRaw = String(
  pickFirst(raw.type, raw.mode, raw.gen_mode, raw.generate_mode, 'LIP_SYNC')
).trim().toUpperCase();

const mode = modeRaw === 'VOICE_CLONE' ? 'VOICE_CLONE' : 'LIP_SYNC';
const rhModeValue = mode === 'VOICE_CLONE' ? 2 : 1;

const audioDurationRaw = pickFirst(
  raw.audioDuration,
  raw.audio_duration,
  raw.duration,
  raw.durationMs,
  raw.duration_ms,
  raw.audioLength,
  raw.audio_length
);

let audioDurationSec = parseDurationSeconds(audioDurationRaw);
const taskId = pickFirst(raw.task_id, raw.taskId);
const sourceWidth = parsePositiveNumber(pickFirst(raw.source_width, raw.sourceWidth));
const sourceHeight = parsePositiveNumber(pickFirst(raw.source_height, raw.sourceHeight));
const targetWidth = parsePositiveNumber(pickFirst(raw.target_width, raw.targetWidth));
const targetHeight = parsePositiveNumber(pickFirst(raw.target_height, raw.targetHeight));
const aspectRatio = parsePositiveNumber(pickFirst(raw.aspect_ratio, raw.aspectRatio));

const runninghubWorkflowId = String(
  pickFirst(raw.rh_workflow_id, raw.rhWorkflowId, '2050237993176322049')
).trim();
const runninghubWorkflowIdLt16 = String(
  pickFirst(raw.rh_workflow_id_lt16, raw.rhWorkflowIdLt16, '')
).trim();
const runninghubWorkflowId16to32 = String(
  pickFirst(raw.rh_workflow_id_16_32, raw.rhWorkflowId16to32, '')
).trim();

const passthrough = {
  record_id: pickFirst(raw.record_id, raw.recordId),
  app_id: pickFirst(raw.app_id, raw.appId),
  app_secret: pickFirst(raw.app_secret, raw.appSecret),
  table_id: pickFirst(raw.table_id, raw.tableId),
  base_id: pickFirst(raw.base_id, raw.baseId),
  user_id: pickFirst(raw.user_id, raw.userId),
  request_id: pickFirst(raw.request_id, raw.requestId),
  task_name: pickFirst(raw.task_name, raw.taskName),
  ext: raw.ext && typeof raw.ext === 'object' ? raw.ext : {}
};

if (!apiKey) {
  throw new Error('缺少 api_key');
}

if (!videoUrl) {
  throw new Error('缺少视频地址：请传 body.videoUrl / video_url');
}
if (!/^https?:\/\//i.test(videoUrl)) {
  throw new Error('videoUrl 必须是 http/https 地址');
}

if (mode === 'LIP_SYNC') {
  if (!audioUrl) {
    throw new Error('LIP_SYNC 模式缺少音频地址：请传 body.audioUrl / audio_url');
  }
  if (!/^https?:\/\//i.test(audioUrl)) {
    throw new Error('audioUrl 必须是 http/https 地址');
  }
  if (audioDurationSec == null || !Number.isFinite(audioDurationSec) || audioDurationSec <= 0) {
    throw new Error('LIP_SYNC 模式缺少可用的音频时长：请传 body.audioDuration（秒）或 durationMs（毫秒）');
  }
}

if (mode === 'VOICE_CLONE') {
  if (!voiceRefAudioUrl) {
    throw new Error('VOICE_CLONE 模式缺少音色参考音频：请传 voice_ref_audio_url');
  }
  if (!/^https?:\/\//i.test(voiceRefAudioUrl)) {
    throw new Error('voice_ref_audio_url 必须是 http/https 地址');
  }
  if (emoRefAudioUrl && !/^https?:\/\//i.test(emoRefAudioUrl)) {
    throw new Error('emo_ref_audio_url 必须是 http/https 地址');
  }
  if (!scriptContent) {
    throw new Error('VOICE_CLONE 模式缺少 script_content');
  }

  if (audioDurationSec == null || !Number.isFinite(audioDurationSec) || audioDurationSec <= 0) {
    audioDurationSec = estimateTtsDuration(scriptContent);
  }

  if (audioDurationSec == null || !Number.isFinite(audioDurationSec) || audioDurationSec <= 0) {
    throw new Error('VOICE_CLONE 模式无法得到有效时长，请补传 audio_duration');
  }
}

return [{
  json: {
    mode,
    rhModeValue,
    videoUrl,
    audioUrl,
    voiceRefAudioUrl,
    emoRefAudioUrl,
    scriptContent,
    callbackUrl,
    runninghubKey,
    apiKey,
    workflowIdFromUser,
    workflowName,
    audioDurationSec,
    taskId,
    sourceWidth,
    sourceHeight,
    targetWidth,
    targetHeight,
    aspectRatio,
    runninghubWorkflowId,
    runninghubWorkflowIdLt16,
    runninghubWorkflowId16to32,
    passthrough
  }
}];

const j = $('输入清洗与校验').item.json || {};

return [{
  json: {
    ...j,
    workflowId: '2050237993176322049',
    workflowRule: 'fixed'
  }
}];

const cfg = $('Config').item.json || {};
const inputMeta = $('按音频时长选择工作流').item.json || {};

const apiKey = cfg.runninghub_key;
const workflowId = cfg.workflow_id;
const webhookUrl = cfg.callback_url;

const videoUrl = cfg.video_url;
const audioUrl = cfg.audio_url;
const voiceRefAudioUrl = cfg.voice_ref_audio_url;
const emoRefAudioUrl = cfg.emo_ref_audio_url;
const scriptContent = cfg.script_content || '';
const workflowRule = cfg.workflow_rule || '';
const mode = String(cfg.mode || 'LIP_SYNC').toUpperCase();
const rhModeValue = String(cfg.rh_mode_value || (mode === 'VOICE_CLONE' ? '2' : '1'));
const audioDurationSec = inputMeta.audioDurationSec;
const targetWidth = Number(inputMeta.targetWidth);
const targetHeight = Number(inputMeta.targetHeight);
const sourceWidth = Number(inputMeta.sourceWidth);
const sourceHeight = Number(inputMeta.sourceHeight);
const aspectRatio = Number(inputMeta.aspectRatio);

const digitalHumanTaskId =
  $('输入清洗与校验').item.json.taskId ||
  $('输入清洗与校验').item.json.task_id ||
  inputMeta.passthrough?.task_id ||
  inputMeta.passthrough?.record_id ||
  '';

if (!apiKey) throw new Error('缺少 runninghub_key');
if (!workflowId) throw new Error('缺少 workflow_id');
if (!webhookUrl) throw new Error('缺少 callback_url');
if (!videoUrl) throw new Error('缺少 video_url');

const nodeInfoList = [
  {
    nodeId: '228',
    fieldName: 'video',
    fieldValue: String(videoUrl)
  },
  {
    nodeId: '336',
    fieldName: 'value',
    fieldValue: String(rhModeValue)
  }
];

if (Number.isFinite(targetWidth) && targetWidth > 0 && Number.isFinite(targetHeight) && targetHeight > 0) {
  nodeInfoList.push(
    {
      nodeId: '327',
      fieldName: 'value',
      fieldValue: String(Math.round(targetWidth))
    },
    {
      nodeId: '326',
      fieldName: 'value',
      fieldValue: String(Math.round(targetHeight))
    }
  );
}

if (mode === 'LIP_SYNC') {
  if (!audioUrl) throw new Error('LIP_SYNC 模式缺少 audio_url');

  nodeInfoList.push({
    nodeId: '125',
    fieldName: 'audio',
    fieldValue: String(audioUrl)
  });
}

if (mode === 'VOICE_CLONE') {
  if (!voiceRefAudioUrl) throw new Error('VOICE_CLONE 模式缺少 voice_ref_audio_url');
  if (!scriptContent) throw new Error('VOICE_CLONE 模式缺少 script_content');

  nodeInfoList.push(
    {
      nodeId: '328',
      fieldName: 'value',
      fieldValue: String(scriptContent)
    },
    {
      nodeId: '329',
      fieldName: 'audio',
      fieldValue: String(voiceRefAudioUrl)
    }
  );

  if (emoRefAudioUrl) {
    nodeInfoList.push({
      nodeId: '330',
      fieldName: 'audio',
      fieldValue: String(emoRefAudioUrl)
    });
  }
}

const payload = {
  apiKey: String(apiKey),
  workflowId: String(workflowId),
  nodeInfoList,
  webhookUrl: String(webhookUrl)
};

if (digitalHumanTaskId) {
  payload.clientId = String(digitalHumanTaskId);
}

return [{
  json: {
    ...payload,
    passthrough: inputMeta.passthrough || {},
    route: {
      mode,
      rhModeValue,
      audioDurationSec,
      workflowRule,
      workflowId,
      sourceWidth: Number.isFinite(sourceWidth) && sourceWidth > 0 ? sourceWidth : null,
      sourceHeight: Number.isFinite(sourceHeight) && sourceHeight > 0 ? sourceHeight : null,
      targetWidth: Number.isFinite(targetWidth) && targetWidth > 0 ? Math.round(targetWidth) : null,
      targetHeight: Number.isFinite(targetHeight) && targetHeight > 0 ? Math.round(targetHeight) : null,
      aspectRatio: Number.isFinite(aspectRatio) && aspectRatio > 0 ? aspectRatio : null
    },
